SELECT 
FROM ai_capability_approval
WHERE tenant_id = #{tenantId} AND client_id = #{clientId}
  AND capability_id = #{capabilityId} AND idempotency_key = #{idempotencyKey}
  AND del_flag = 0
LIMIT 1

SELECT 
FROM ai_capability_approval
WHERE tenant_id = #{tenantId} AND id = #{id} AND client_id = #{clientId}
  AND actor_user_id = #{actorUserId} AND service_user_id = #{serviceUserId}
  AND active_org_id = #{activeOrgId} AND del_flag = 0
LIMIT 1
